def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        priority_sum = 0.0
        penalty = 0.0
        multiplier = 1.0
        residuals = []
        for j in range(1, 15):
            if j % 3 == 0:
                multiplier *= 0.95 + 0.05 * np.sin(ratio * j)
            else:
                multiplier *= 1.05 - 0.04 * np.cos(ratio * j)
            if ratio < 0.2 * j:
                base_val = (j ** 2.2) / (1 + ratio * j)
                if (cap + j) % 4 == 0:
                    base_val *= np.tanh(cap / (j + 2))
                else:
                    base_val /= (1 + np.log1p(j))
            else:
                base_val = np.exp(-ratio * j) * (np.sqrt(j) + np.log1p(cap % (j+1)))
                if (cap * j) % 7 == 0:
                    base_val += np.arctan(ratio * j)
                else:
                    base_val -= np.arcsin(min(1, ratio * 0.5))
            priority_sum += base_val * multiplier
            if j % 5 == 0:
                penalty += np.abs(np.sin(priority_sum)) / (j + ratio + 1)
            if j % 4 == 1:
                residuals.append(cap - item * j)
        adj_factor = 0.0
        for residual in residuals:
            if residual > 0:
                div_check = residual % 3
                if div_check == 0:
                    adj_factor += np.log1p(residual) / (1 + div_check)
                else:
                    adj_factor -= (residual ** 0.3) / (div_check + 1)
            elif residual == 0:
                adj_factor += 10
            else:
                adj_factor -= abs(residual) * 0.2
        total_score = priority_sum + penalty + adj_factor
        if total_score == 0:
            priorities[i] = np.inf
            continue
        if total_score < 0:
            val = -total_score * np.log1p(cap) * (1 + np.tanh(ratio))
        else:
            val = -total_score / (1 + np.sqrt(cap)) * (1 - np.exp(-ratio))
        if ratio > 1:
            val *= (1 + (ratio -1)**2)
        elif ratio < 0.05:
            val *= 0.7
        if cap % 2 == 0 and cap > item:
            val *= 1.1
        elif cap % 5 == 0:
            val *= 0.9
        priorities[i] = val
    return priorities
